pub fn commit_index_batch(store: &mut GraphStore, batch: IndexBatch) -> Result<CommitStats> {
    let transaction = store.connection.transaction()?;
    let mut stats = CommitStats::default();
    for file in batch.files {
        let file_id = upsert_file(&transaction, &file.path, file.content_hash)?;
        delete_stale_symbols(&transaction, file_id, &file.symbol_ids)?;
        for symbol in file.symbols {
            let symbol_id = upsert_symbol(&transaction, file_id, &symbol)?;
            stats.symbols += 1;
            for reference in symbol.references {
                insert_reference(&transaction, symbol_id, reference)?;
                stats.references += 1;
            }
        }
        stats.files += 1;
    }
    transaction.commit()?;
    store.refresh_generation()?;
    Ok(stats)
}

export async function connectInferenceDaemon(options: ConnectOptions): Promise<DaemonClient> {
  const deadline = Date.now() + options.timeoutMs;
  let attempt = 0;
  let lastError: unknown;
  while (Date.now() < deadline) {
    attempt += 1;
    try {
      const socket = await openSocket(options.endpoint);
      const client = new DaemonClient(socket);
      const hello = await client.handshake({ protocol: PROTOCOL_VERSION });
      if (hello.modelHash !== options.expectedModelHash) {
        await client.close();
        throw new Error(`model hash mismatch: ${hello.modelHash}`);
      }
      return client;
    } catch (error) {
      lastError = error;
      const delay = Math.min(25 * 2 ** (attempt - 1), 250);
      await sleep(delay);
    }
  }
  throw new DaemonUnavailableError(options.endpoint, attempt, lastError);
}

func (c *Cache) EvictToLimit(ctx context.Context, limit int64) (int, error) {
    c.mu.Lock()
    defer c.mu.Unlock()
    entries, err := c.store.ListByLastAccess(ctx)
    if err != nil {
        return 0, fmt.Errorf("list cache entries: %w", err)
    }
    current := c.totalBytes(entries)
    removed := 0
    for _, entry := range entries {
        if current <= limit {
            break
        }
        if entry.Locked || c.active[entry.Key] > 0 {
            continue
        }
        if err := os.RemoveAll(entry.Path); err != nil {
            return removed, fmt.Errorf("remove %s: %w", entry.Key, err)
        }
        if err := c.store.Delete(ctx, entry.Key); err != nil {
            return removed, fmt.Errorf("delete metadata %s: %w", entry.Key, err)
        }
        current -= entry.Size
        removed++
    }
    return removed, nil
}
